class Solution(object):
    def countNicePairs(self, nums):
        MOD = 10**9 + 7
        def rev(n):
            r = 0
            while n > 0:
                r = r * 10 + n % 10
                n //= 10
            return r
        freq = {}
        result = 0
        for num in nums:
            diff = num - rev(num)
            result = (result + freq.get(diff, 0)) % MOD
            freq[diff] = freq.get(diff, 0) + 1
        return result
